const uploadPublicLogFiles=async()=>{if(!ST.logFiles.length)return[];const out=[],u=(await s.auth.getUser()).data.user;for(const file of ST.logFiles){if((file.size||0)>20*1024*1024)throw new Error(`Archivo demasiado grande: ${file.name}`);const safe=file.name.normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g,"_").replace(/[^a-zA-Z0-9._()-]/g,"");const path=`${ID}/soporte_${Date.now()}_${crypto.randomUUID()}_${safe}`;const up=await s.storage.from("soporte_adjuntos").upload(path,file,{contentType:file.type||"application/octet-stream",upsert:false});if(up.error)throw up.error;const legacy=await s.from("ticket_archivos").insert({ticket_id:ID,nombre_archivo:file.name,url_archivo:path,mime_type:file.type||null,tamano_bytes:file.size,subido_por:u?.id||null});if(legacy.error)console.error("LEGACY_TICKET_ARCHIVOS_ERROR",legacy.error.message);const canon=await s.from("archivos_ticket").insert({ticket_id:ID,origen:"interno",visibilidad:"publica",nombre_archivo:file.name,storage_path:path,url_firma:null,mime_type:file.type||null,tamano_bytes:file.size,subido_por:u?.id||null,meta:{canal:"ticket_interno",folio:T?.folio||null}});if(canon.error)throw canon.error;out.push({nombre:file.name,tipo:file.type||null,peso:file.size,storage_path:path,url:null,origen:"soporte_interno"})}return out};

const nextStep=t=>{const s=ticketStateKey(t?.estado),d=norm(`${t?.titulo||""} ${t?.descripcion||""}`);if(s==="esperando_cliente")return"Esperar respuesta del cliente";if(s==="resuelto")return"Cerrar al confirmar";if(d.includes("xml"))return"Pedir XML";if(d.includes("captura")||d.includes("pantalla"))return"Revisar evidencia";if(d.includes("remoto")||d.includes("anydesk")||d.includes("teamviewer"))return"Coordinar acceso remoto";return s==="abierto"?"Hacer triage":"Dar seguimiento"};
const anydeskFromText=t=>{const x=String(t?.contexto_adicional||"").match(/AnyDesk:\s*([^\n]+)/i);return x?.[1]?.trim()||""};
const anydeskAccess=()=>CLIENT_ACCESSES.find(x=>norm(x.tipo)==="anydesk"&&x.activo!==false)||null;
const anydeskOf=t=>anydeskAccess()?.valor||anydeskFromText(t)||"";
const loadClientAccesses=async()=>{if(!T?.cliente_id)return[];const{data,error}=await s.from("cliente_accesos").select("*").eq("cliente_id",T.cliente_id).eq("activo",true).order("actualizado_en",{ascending:false});if(error){console.error("LOAD_CLIENT_ACCESSES_ERROR",error);return[]}return Array.isArray(data)?data:[]};
const renderAnyDeskPill=()=>{const ad=anydeskOf(T),pill=$("#tkAnyDeskPill"),txt=$("#tkAnyDesk"),btn=$("#tkCopyAnyDeskBtn img");if(!pill||!txt)return;txt.textContent=ad||"Agregar acceso";pill.classList.toggle("has-access",!!ad);pill.classList.toggle("no-access",!ad);if(btn)btn.src=ad?"../IMG/copy.png":"../IMG/mas.png"};
const saveAnyDeskAccess=async()=>{if(!T?.cliente_id)return toast("Primero liga el cliente.","warn");const cur=anydeskOf(T),val=prompt(cur?"Actualizar AnyDesk / acceso remoto:":"Agregar AnyDesk / acceso remoto:",cur||"");if(val===null)return;const clean=String(val||"").trim();if(!clean)return toast("No se guardó porque quedó vacío.","warn");setBusy(true);try{const u=(await s.auth.getUser()).data.user,old=anydeskAccess(),payload={cliente_id:T.cliente_id,contacto_id:T?.contacto_id||null,tipo:"anydesk",valor:clean,etiqueta:"AnyDesk",activo:true,actualizado_en:new Date().toISOString(),actualizado_por:u?.id||null};const r=old?.id?await s.from("cliente_accesos").update(payload).eq("id",old.id):await s.from("cliente_accesos").insert(payload);if(r.error)throw r.error;const extra=String(T?.contexto_adicional||"").replace(/(^|\n)\s*AnyDesk:\s*[^\n]*/ig,"").trim(),nextExtra=`${extra}${extra?"\n":""}AnyDesk: ${clean}`;                                                                                                                                                                                                                                                                                                                                                                        const up=await s.from("tickets").update({contexto_adicional:nextExtra,fecha_actualizacion:new Date().toISOString()}).eq("id",ID).select().single();if(up.error)throw up.error;T=up.data;CLIENT_ACCESSES=await loadClientAccesses();renderContext();toast("AnyDesk guardado para el cliente.","ok")}catch(err){console.error("SAVE_ANYDESK_ACCESS_ERROR",err);toast(msg(err),"bad")}finally{setBusy(false)}};
