const openSide=()=>document.body.classList.add("tk-side-open");
const closeSide=()=>document.body.classList.remove("tk-side-open");

const bindGlobalClicks=()=>{document.addEventListener("click",async e=>{const hp=e.target.closest("[data-heat-days]");if(hp){HEAT.periodDays=Number(hp.dataset.heatDays)||30;renderHeat();return}const sideBtn=e.target.closest("#tkSideToggle");if(sideBtn)return openSide();const sideClose=e.target.closest("#tkSideClose");if(sideClose)return closeSide();const contactMore=e.target.closest("#tkContactMoreBtn");if(contactMore)return openContactPanel();const avInfo=e.target.closest("#tkAvailabilityInfo");if(avInfo){e.preventDefault();const r=avInfo.getBoundingClientRect(),p=document.createElement("div");p.className="tk-info-pop";p.textContent=T?.horario_notas||T?.horario_contacto||"Sin nota adicional de horario.";document.body.appendChild(p);p.style.left=Math.min(r.left,innerWidth-260)+"px";p.style.top=Math.max(12,r.top-54)+"px";setTimeout(()=>p.remove(),2600);return}const contactDot=e.target.closest("#tkContactDot");if(contactDot){e.preventDefault();e.stopPropagation();return openContactPanel()}const contactTop=e.target.closest("#tkContactCollapse");if(contactTop){$("#tkContactFold").open=false;return}const contactClose=e.target.closest("#tkContactClose");if(contactClose)return closeContactPanel();if(document.body.classList.contains("tk-side-open")&&!e.target.closest(".ticket-side")&&!e.target.closest("#tkSideToggle"))return closeSide();const qrc=e.target.closest("#tkQrClose");if(qrc)return qrClose();const qrm=e.target.closest("[data-qr-mode]");if(qrm){qrCollect();QR_STATE.mode=qrm.dataset.qrMode;await qrLoad();qrRender();return}const qrs=e.target.closest("[data-qr-scope]");if(qrs){qrCollect();QR_STATE.scope=qrs.dataset.qrScope;if(QR_STATE.scope==="cliente"&&!qrClientId())return toast("Este ticket no tiene cliente ligado.","warn");await qrLoad();qrRender();return}const qra=e.target.closest("#tkQrAdd");if(qra)return qrAdd();const qrg=e.target.closest("#tkQrSaveAll");if(qrg)return qrSaveAll();const qrx=e.target.closest("[data-qr-act]");if(qrx){const row=qrx.closest(".tk-qr-row"),i=+row.dataset.i,id=row.dataset.id||"",act=qrx.dataset.qrAct;qrCollect();if(act==="up"){if(i>0){[QRM.rows[i-1],QRM.rows[i]]=[QRM.rows[i],QRM.rows[i-1]];qrPaintEditor()}return}if(act==="down"){if(i<QRM.rows.length-1){[QRM.rows[i+1],QRM.rows[i]]=[QRM.rows[i],QRM.rows[i+1]];qrPaintEditor()}return}if(act==="use"){applyQuickReply("__txt__"+(QRM.rows[i]?.texto||""));return qrClose()}if(act==="del"){try{if(id)await qrSoftDelete(id);QRM.rows.splice(i,1);qrPaintEditor()}catch(err){toast(msg(err),"bad")}return}}if(e.target?.id==="tkQrOverlay")return qrClose();const gear=e.target.closest("#tkThreadGearBtn");if(gear){e.preventDefault();e.stopPropagation();applyNotifUi();return toggleThreadGear()}const mute=e.target.closest("#tkMuteTicketBtn");if(mute){e.preventDefault();saveTicketMute(!ST.ticketMuted);return}const editSys=e.target.closest("[data-sys-edit]");if(editSys){const rec=CLIENT_SYSTEMS.find(x=>String(x.id)===String(editSys.dataset.sysEdit));if(rec)openSystemPanel(rec);return}const qt=e.target.closest("[data-qr-text]");if(qt)return applyQuickReply("__txt__"+qt.dataset.qrText);const qe=e.target.closest("#tkQrEditBtn");if(qe)return openQrEditor();const q=e.target.closest("[data-qr]");if(q)return applyQuickReply(q.dataset.qr);const copyAny=e.target.closest("#tkCopyAnyDeskBtn");if(copyAny){const ad=anydeskOf(T);if(!ad)return saveAnyDeskAccess();try{await navigator.clipboard.writeText(ad);toast("AnyDesk copiado.","ok")}catch{return saveAnyDeskAccess()}return}const m=e.target.closest("[data-ev-menu]");if(m){e.preventDefault();e.stopPropagation();const box=$(`#evMenu${m.dataset.evMenu}`);closeFileMenus();return box?.classList.toggle("open")}const c=e.target.closest("[data-ev-close]");if(c){e.preventDefault();return closeFileMenus()}const o=e.target.closest("[data-ev-open]");if(o)return openEvidence(+o.dataset.evOpen);const openNew=e.target.closest("[data-ev-open-new]");if(openNew){const f=FILES[+openNew.dataset.evOpenNew],u=await signedEvidenceUrl(f);if(u)window.open(u,"_blank","noopener");closeFileMenus();return}const dl=e.target.closest("[data-ev-download]");if(dl){const f=FILES[+dl.dataset.evDownload],u=await signedEvidenceUrl(f);if(u){const a=document.createElement("a");a.href=u;a.download=f.nombre||"archivo";document.body.appendChild(a);a.click();a.remove()}closeFileMenus();return}const cp=e.target.closest("[data-ev-copy]");if(cp){const f=FILES[+cp.dataset.evCopy],u=await signedEvidenceUrl(f);if(u)await navigator.clipboard.writeText(u).catch(()=>{}),toast("Enlace copiado","ok");closeFileMenus();return}if(!e.target.closest(".ev-menu-wrap"))closeFileMenus();if(!e.target.closest(".thread-gear-wrap"))toggleThreadGear(false);if(e.target===document.querySelector("#evModal"))hideEv()});document.addEventListener("keydown",e=>{if(e.key==="Escape"){if(document.body.classList.contains("tk-side-open"))return closeSide();const qrOpen=!$("#tkQrOverlay")?.hidden,evOpen=!$("#evModal")?.hidden,menuOpen=!!document.querySelector(".ev-menu.open"),contactOpen=!$("#tkContactOverlay")?.hidden,sysOpen=!$("#tkSystemOverlay")?.hidden;if(qrOpen)return qrClose();if(evOpen)return hideEv();if(contactOpen)return closeContactPanel();if(sysOpen)return closeSystemPanel();if(menuOpen)return closeFileMenus()}})};




const bind=()=>{if(document.documentElement.dataset.ticketBound)return;document.documentElement.dataset.ticketBound="1";bindComposer();bindFolds();bindIdentity();bindSystems();bindChrome();bindGlobalClicks()};
document.addEventListener("DOMContentLoaded",()=>{bind();renderLogFilesMeta();renderComposerMode();setComposerMode("seguimiento","");load().catch(err=>toast(msg(err),"bad"));startTicketPolling()});window.addEventListener("beforeunload",stopTicketPolling,{passive:true});

